import network
import time
from machine import Pin, ADC
from umqtt.simple import MQTTClient

# WiFi configuration
ssid = 'your_SSID'
password = 'your_PASSWORD'
mqtt_broker = 'broker_ip'
client_id = 'esp32_sensor_client'

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(ssid, password)
    while not wlan.isconnected():
        time.sleep(1)
    print('WiFi connected:', wlan.ifconfig())

# Read temperature from ADC
def read_temperature():
    adc = ADC(Pin(34))  # Adjust pin as needed
    adc.atten(ADC.ATTN_11DB)  # Set range
    voltage = adc.read() * (3.3 / 4095)  # Convert ADC reading to voltage
    temperature = (voltage - 0.5) * 100  # Convert voltage to temperature Celsius
    return temperature

# Publish temperature data
def publish_temperature(client):
    temperature = read_temperature()
    client.publish(b'sensors/temp', str(temperature).encode())
    print('Published temperature:', temperature)

# Main function
def main():
    connect_wifi()
    client = MQTTClient(client_id, mqtt_broker)
    client.connect()
    
    while True:
        publish_temperature(client)
        time.sleep(10)  # Adjust publishing interval as needed

main()